package com.careeros.search.web;import com.careeros.search.application.*;import com.careeros.search.domain.*;import com.careeros.common.web.PageResponse;import com.careeros.job.web.*;import jakarta.validation.constraints.*;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/saved-searches")public class SavedSearchController{private final SavedSearchService s;public SavedSearchController(SavedSearchService s){this.s=s;}@PostMapping public Response create(@RequestBody Request r){return out(s.save(null,cmd(r)));}@GetMapping public PageResponse<Response>list(Pageable p){return PageResponse.from(s.list(p),this::out);}@GetMapping("/{id}")public Response get(@PathVariable UUID id){return out(s.get(id));}@PutMapping("/{id}")public Response update(@PathVariable UUID id,@RequestBody Request r){return out(s.save(id,cmd(r)));}@PostMapping("/{id}/execute")public PageResponse<JobPostingResponse>execute(@PathVariable UUID id,Pageable p){return PageResponse.from(s.execute(id,p),JobPostingMapper::toResponse);}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)public void delete(@PathVariable UUID id){s.delete(id);}private SavedSearchService.Command cmd(Request r){return new SavedSearchService.Command(r.name,r.title,r.sorting,r.minimumScore,r.remote,r.companies,r.locations,r.technologies);}private Response out(SavedSearch x){return new Response(x.getId(),x.getName(),x.getTitle(),x.getSorting(),x.getMinimumScore(),x.getRemote(),x.getCompanies(),x.getLocations(),x.getTechnologies());}public record Request(@NotBlank String name,String title,String sorting,@Min(0)@Max(100)Integer minimumScore,Boolean remote,List<UUID>companies,List<String>locations,List<String>technologies){}public record Response(UUID id,String name,String title,String sorting,Integer minimumScore,Boolean remote,List<UUID>companies,List<String>locations,List<String>technologies){}}
